ALTER TABLE Races ADD COLUMN IF NOT EXISTS Description TEXT;
UPDATE Races SET Description = '' WHERE Description <> '';
ALTER TABLE Races ALTER COLUMN Description SET NOT NULL;

UPDATE Races SET Description = 'Feeling frisky? Test your legs at 1600 meters on any standard track in the world (just 9 meters short of a mile—we’ll round up for mileage calculations). You can run the Sweet 1600 in FLRC’s summer track meets for some competition, and it’s a great way to continue to rack up Challenge efforts while you’re traveling.' WHERE Name = 'Sweet 1600';
UPDATE Races SET Description = 'Easy and fast, this 1-mile slight downhill course is a favorite of speedsters and walkers alike. Try for a mile personal record!' WHERE Name = 'East Hill Rec Way';
UPDATE Races SET Description = 'Never run trails before? This course is short, but it will introduce you to trail navigation, terrain, and yes, multiple stream crossings just a few miles from Ithaca.' WHERE Name = 'Ellis Hollow Creek Crossings';
UPDATE Races SET Description = 'What could be lovelier than a run around the glorious F. R. Newman Arboretum in spring, summer, or fall?' WHERE Name = 'Cornell Botanic Gardens';
UPDATE Races SET Description = 'Never run trails before? This course in the heart of one of Ithaca’s iconic gorges is short, but it features plenty of varied terrain to introduce you to trail navigation.' WHERE Name = 'Mulholland Waterfalls';
UPDATE Races SET Description = 'Never run trails before? This course is short and easy, but it will introduce you to trail navigation in the pretty scenery surrounding Cornell’s world-famous Lab of Ornithology.' WHERE Name = 'Duck Trails';
UPDATE Races SET Description = 'For those in downtown Ithaca, this course on Cass Park and the Allan H. Treman State Marine Park trails provides a flat 5K with no cars. Like the Sweet 1600, you can substitute race results from any 5K or parkrun for this course during the Challenge—a report on remote races is required this year!—so you can keep up with the Challenge while on vacation.' WHERE Name = 'Lakefront Loops 5K';
UPDATE Races SET Description = 'Starting and finishing at the east end of the Waterfront Trail in Stewart Park, this flat out-and-back course takes you along the shore of Cayuga Lake and past the golf course.' WHERE Name = 'Waterfront Trail';
UPDATE Races SET Description = 'To give everyone a sense of classic cross-country running, this loopy course takes you on mown paths around fields. You’ll want to run this one multiple times after you get your bearings.' WHERE Name = 'Lansing Center Trail';
UPDATE Races SET Description = 'Those returning from last year will remember some of this course, which now takes in some trails within the F. R. Newman Arboretum and extends out around Cornell’s scenic Beebe Lake.' WHERE Name = 'Beebe Lake';
UPDATE Races SET Description = 'This course takes us to a new Finger Lakes Land Trust trail north of Lansing that offers rolling meadows and a few steep forest trails.' WHERE Name = 'Cayuga Cliffs';
UPDATE Races SET Description = 'The Lindsay-Parsons Biodiversity Preserve south of Ithaca has 554 acres and several miles of trails leading to a forest, lake, and beaver pond. We’ve set a 4.3-mile course you can run twice if you want more miles for the drive.' WHERE Name = 'Lindsay-Parsons';
UPDATE Races SET Description = 'The Lime Hollow Nature Center on the Ithaca side of Cortland has a bunch of lovely trails—we’ve carved out a 4.5-mile loop that you can run twice if you want more miles for the drive.' WHERE Name = 'Lime Hollow';
UPDATE Races SET Description = 'You can’t beat the view of Taughannock Falls, one of the area’s iconic destinations. At 215 feet high, Taughannock is even taller than Niagara Falls, and you get to run the rim trails and all the way to the base of the falls. Yes, there are hills.' WHERE Name = 'Taughannock Rim & Falls';
UPDATE Races SET Description = 'With a starting point at the Stevenson Road intersection of the Dryden Rail Trail, this course crossing the famous FH Fox 4Ever bridge over Route 366 offers a scenic trail option for those at Cornell looking to get a run in before work, at lunch, or after work.' WHERE Name = 'FH Fox';
UPDATE Races SET Description = 'With a starting point in the F. R. Newman Arboretum, this course heads toward Beebe Lake before climbing the stairs to North Campus and running around the A Lot, where it shows you the Palmer Woods Trail into Cayuga Heights. From there, you’ll head back into Cornell and up Tower Road.' WHERE Name = 'Cornell Scenic Circuit';
UPDATE Races SET Description = 'For those at Cornell looking to get a run in before work, at lunch, or after work, this course combines familiar paths and roads around the Cornell Botanic Gardens with a detour to some less well-known trails on the north side of Fall Creek.' WHERE Name = 'Fall Creek Trails';
UPDATE Races SET Description = 'Buttermilk State Park hosts this traditional FLRC trail race course, which rewards those who climb the hill with beautiful trails at Upper Buttermilk.' WHERE Name = 'Tortoise and Hare';
UPDATE Races SET Description = 'We couldn’t resist revisiting one of our favorite state forests at Hammond Hill. This year, however, we’re doing the longer course from our Super Frosty Loomis snowshoe race.' WHERE Name = 'Long Loomis';
UPDATE Races SET Description = 'You’ll experience all the elevation between Cornell University on the hill and the City of Ithaca by the lake. This course takes in downtown Ithaca, Collegetown, the Cascadilla Gorge Trail, Cornell campus, and Cayuga Heights, plus you’ll go by four Ithaca schools.' WHERE Name = 'Town & Gown Up & Down';
UPDATE Races SET Description = 'A classic autumn FLRC trail race, this 6-mile course in the Danby State Forest takes you on the scenic Abbott Loop.' WHERE Name = 'Danby Down & Dirty';
UPDATE Races SET Description = 'This downtown Ithaca course takes you out and back on the shores of the Cayuga Inlet, through Cass Park and around the trails at Allan H. Treman State Marine Park. It’s a great mix of urban and natural running with no major road crossings.' WHERE Name = 'Inlet Shore Trail';
UPDATE Races SET Description = 'We return to Brooktondale for this road course, which starts at the Brookton Market and takes you on two loops of the countryside, including the lovely views from Burns Road.' WHERE Name = 'Valley Views';
UPDATE Races SET Description = 'This course mixes the South Hill Rec Way with a couple of singletrack trail loops between the Rec Way and the Six Mile Creek reservoir. We bet most of you have never explored these before!' WHERE Name = 'Six Mile Creek';
UPDATE Races SET Description = 'Start at the playground and run out and back on all three legs of the South Hill Rec Way in any order you want for this course.' WHERE Name = 'South Hill Rec Way';
UPDATE Races SET Description = 'Incorporating last year’s downhill East Hill Rec Way mile, this course adds in the Dryden Rail Trail, taking you all the way out to Route 13 and back.' WHERE Name = 'East Hill Dryden Rail Trail';
UPDATE Races SET Description = 'This course starts at the Finger Lakes Land Trust parking area for Lick Brook near the base of Treman State Park, then climbs the Lick Brook hills before making its way over to Buttermilk State Park for a loop around Lake Treman.' WHERE Name = 'Treman Trailipop';
UPDATE Races SET Description = 'You’ll be familiar with this course if you’ve run the 23K distance at the Danby Down & Dirty trail race. If not, prepare to experience the scenic Abbott Loop in the Danby State Forest, complete with long views from the Pinnacles.' WHERE Name = 'Abbott Ascent';
UPDATE Races SET Description = 'Starting smack in the village of Dryden, this course takes you out and back on another old railroad bed for a flat, fast run through wetlands and alongside Dryden Lake.' WHERE Name = 'Jim Schug Trail';
UPDATE Races SET Description = 'The Black Diamond Trail is an FLRC Challenge favorite thanks to its central location, minimal elevation change, and smooth surface. This year, you can once again run the entire trail in either direction or turn around halfway.' WHERE Name = 'Black Diamond Cass to Gorge';
UPDATE Races SET Description = 'Starting at the Blueberry Patch Campground in the Finger Lakes National Forest, this trail takes in portions of the popular Finger Lakes 50s ultra course. Points for finding wild blueberries!' WHERE Name = 'Blueberry Patch';
UPDATE Races SET Description = 'You’ll head out toward Dryden to Hammond Hill State Forest for the Thom B. Trail Run course, another longtime FLRC trail race.' WHERE Name = 'Thom B. Trail Run';
UPDATE Races SET Description = 'Some of the best running trails in the area are at Hammond Hill, and this course takes you on some that you may never have seen before!' WHERE Name = 'Hammond Hill Hoctathon';
UPDATE Races SET Description = 'Kennedy State Forest in Virgil is your destination for FLRC’s popular Forest Frolic course on the other side of Greek Peak.' WHERE Name = 'Forest Frolic 15K';
UPDATE Races SET Description = 'This classic course for Ithaca marathoners and Cornell cross-country runners combines long distances and challenging hills on quiet country roads. Don’t count the humps, but if you run it the RunGo way, you’ll enjoy a long downhill at the end.' WHERE Name = 'Triple Hump';
UPDATE Races SET Description = 'You want to run long, and you want to keep it on roads. This course takes you through the rolling hills and valleys of Brooktondale, starting and finishing at Brookton’s Market.' WHERE Name = 'Brookton Hill & Dale';
UPDATE Races SET Description = 'Few people know about Ludlowville Falls, but you’ll start at Ludlowville Park and then run out the scenic Salmon Creek Road before climbing Brooks Hill Road to return on the ridge, enjoying glorious views the entire way. Or run it the other way to hit the hill early.' WHERE Name = 'Ludlowville Loop';
UPDATE Races SET Description = 'The Black Diamond Trail is an FLRC Challenge favorite, so this long Trumansburg-focused course incorporates some of the trail along with West Hill roads.' WHERE Name = 'Run Rabbit Run';
UPDATE Races SET Description = 'Our trail monster course for 2025 starts at the Lick Brook parking lot and follows the North Country Trail all the way alongside Robert H. Treman State Park. It’s a long one, but what better way can you think of to spend a summer morning?' WHERE Name = 'North Country Half';
UPDATE Races SET Description = 'Our longest course of the year starts at Campbell Meadow Park and sends you out and around flat roads all the way to the Ithaca airport before you turn and retrace your steps.' WHERE Name = 'Freeville Fly-In';
UPDATE Races SET Description = 'This course uses more of the Dryden Rail Trail, starting in Freeville and running to Dryden and out the Jim Schug Trail, but then sends you around Dryden Lake for the head of the lollipop. It’s long, but flat and non-technical.' WHERE Name = 'Dryden Lake Lollipop';
UPDATE Races SET Description = 'Our longest and toughest course this year follows the Finger Lakes Trail alongside Treman State Park on the west and Lick Brook on the east. Work your way up to this one, and there’s no shame in hiking it.' WHERE Name = 'Lick Brook & Treman FLT';
UPDATE Races SET Description = 'With a start/finish at the Ellis Hollow Community Center, this half marathon follows some of the same route as FLRC’s marquee race, the Skunk Cabbage Classic.' WHERE Name = 'Pseudo Skunk Cabbage';

UPDATE Races SET Description = 'This course has been archived in favor of the newer "Black Diamond Cass to Gorge".' WHERE Name LIKE 'Black Diamond %' AND Description = '';